function staggerRows(rows, max = 8, step = 50) {
  rows.forEach((r, i) => {
    if (i < max) {
      r.style.setProperty('--delay', (i * step) + 'ms');
      r.classList.add('run');
    } else {
      r.style.opacity = 1;
      r.style.transform = 'none';
    }
  });
}

