function revealGrid(grid, step = 80, max = 6) {
  const io = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        const imgs = grid.querySelectorAll('.grid-img');
        imgs.forEach((img, i) => {
          if (i < max) img.style.setProperty('--delay', (i * step) + 'ms');
          img.classList.add('in');
        });
        io.unobserve(grid);
      }
    });
  }, { threshold: 0.1 });
  io.observe(grid);
}

